# Prompt: Build a Python Flask file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
from flask import Flask, request, jsonify, send_file, abort

app = Flask(__name__)

# Configure the upload directory relative to the script's location
# For demonstration, we'll use a 'user_files' directory in the same place as the script.
# In a real application, this would be more robustly configured per user.
# For simplicity, we're assuming a single root for all "user files" for this API.
BASE_UPLOAD_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'user_files')

# Ensure the base directory exists
os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)

# Helper function to get a safe, full path for a given user-provided relative path
def get_safe_full_path(relative_path):
    # Normalize the user-provided path to handle '..' and clean up
    normalized_relative_path = os.path.normpath(relative_path)

    # Prevent directory traversal by checking if the normalized path tries to go outside BASE_UPLOAD_DIR
    # A simple check: if the path starts with '..', it's trying to go up from the root.
    # More robust: check if the final full_path starts with BASE_UPLOAD_DIR.
    if normalized_relative_path.startswith('..') or normalized_relative_path.startswith('/'):
        return None # Invalid path attempting to access outside root

    full_path = os.path.join(BASE_UPLOAD_DIR, normalized_relative_path)

    # Ensure the constructed path is actually within the BASE_UPLOAD_DIR
    # This is the most robust check against directory traversal.
    if not os.path.abspath(full_path).startswith(os.path.abspath(BASE_UPLOAD_DIR)):
        return None

    return full_path

@app.route('/list', methods=['GET'])
def list_directory():
    path = request.args.get('path', '')
    full_path = get_safe_full_path(path)

    if full_path is None:
        return jsonify({"error": "Invalid path provided."}), 400

    if not os.path.exists(full_path):
        return jsonify({"error": "Path not found."}), 404
    
    if not os.path.isdir(full_path):
        return jsonify({"error": "Path is not a directory."}), 400

    items = []
    try:
        for item_name in os.listdir(full_path):
            item_full_path = os.path.join(full_path, item_name)
            relative_item_path = os.path.relpath(item_full_path, BASE_UPLOAD_DIR)
            
            item_info = {
                "name": item_name,
                "path": relative_item_path,
                "type": "directory" if os.path.isdir(item_full_path) else "file",
                "size": os.path.getsize(item_full_path) if os.path.isfile(item_full_path) else None,
                "last_modified": os.path.getmtime(item_full_path)
            }
            items.append(item_info)
    except OSError as e:
        return jsonify({"error": f"Error accessing directory: {str(e)}"}), 500

    return jsonify({"path": path, "items": items})

@app.route('/download', methods=['GET'])
def download_file():
    path = request.args.get('path')
    if not path:
        return jsonify({"error": "File path is required."}), 400

    full_path = get_safe_full_path(path)

    if full_path is None:
        return jsonify({"error": "Invalid path provided."}), 400

    if not os.path.exists(full_path):
        return jsonify({"error": "File not found."}), 404
    
    if not os.path.isfile(full_path):
        return jsonify({"error": "Path is not a file."}), 400

    try:
        return send_file(full_path, as_attachment=True, download_name=os.path.basename(full_path))
    except Exception as e:
        return jsonify({"error": f"Error downloading file: {str(e)}"}), 500

@app.route('/info', methods=['GET'])
def get_file_info():
    path = request.args.get('path')
    if not path:
        return jsonify({"error": "File path is required."}), 400

    full_path = get_safe_full_path(path)

    if full_path is None:
        return jsonify({"error": "Invalid path provided."}), 400

    if not os.path.exists(full_path):
        return jsonify({"error": "Path not found."}), 404

    try:
        stats = os.stat(full_path)
        info = {
            "name": os.path.basename(full_path),
            "path": path,
            "type": "directory" if os.path.isdir(full_path) else "file",
            "size": stats.st_size,
            "last_modified": stats.st_mtime,
            "created": stats.st_ctime,
            "permissions": oct(stats.st_mode & 0o777), # Unix-style permissions
            "is_symlink": os.path.islink(full_path)
        }
        return jsonify(info)
    except OSError as e:
        return jsonify({"error": f"Error getting file info: {str(e)}"}), 500

